namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string ImageUrl { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil." },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti in salted water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture.\n6. Serve immediately with extra pecorino." },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Ginger, Garlic", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté ginger and garlic in butter.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream and add chicken pieces.\n6. Simmer 10 minutes. Serve with naan." },
            new() { Id = 4, Title = "Vegetable Biryani", Category = "Indian", Ingredients = "Basmati rice, Mixed vegetables, Onions, Yogurt, Saffron, Whole spices, Ghee, Mint", Steps = "1. Soak rice 30 minutes, parboil.\n2. Fry onions until golden brown.\n3. Cook vegetables with spices and yogurt.\n4. Layer rice and vegetables in pot.\n5. Add saffron milk and mint.\n6. Seal and cook on low heat 25 minutes." },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheddar cheese, Sour cream, Salsa", Steps = "1. Brown ground beef, drain fat.\n2. Add taco seasoning and water, simmer.\n3. Warm tortillas in dry skillet.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream." },
            new() { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Red onion, Cilantro, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, jalapeño.\n4. Add lime juice, cilantro, and salt.\n5. Serve immediately with tortilla chips." },
            new() { Id = 7, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles, Miso paste, Pork broth, Chashu pork, Soft-boiled egg, Green onions, Nori, Corn", Steps = "1. Simmer pork broth 4 hours.\n2. Whisk miso paste into hot broth.\n3. Cook ramen noodles per package.\n4. Slice chashu pork thinly.\n5. Assemble bowl: noodles, broth, toppings.\n6. Garnish with nori and green onions." },
            new() { Id = 8, Title = "Teriyaki Salmon", Category = "Japanese", Ingredients = "Salmon fillets, Soy sauce, Mirin, Sugar, Ginger, Sesame seeds, Steamed rice", Steps = "1. Mix soy sauce, mirin, sugar, and ginger.\n2. Marinate salmon 30 minutes.\n3. Pan-sear salmon skin-side down 4 min.\n4. Flip and cook 3 more minutes.\n5. Glaze with teriyaki sauce.\n6. Serve over rice with sesame seeds." },
            new() { Id = 9, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs and sugar until fluffy.\n3. Fold in chocolate mixture and flour.\n4. Pour into greased ramekins.\n5. Bake at 425°F for 12 minutes.\n6. Invert onto plates, serve immediately." },
            new() { Id = 10, Title = "Classic Tiramisu", Category = "Desserts", Ingredients = "Ladyfingers, Mascarpone, Espresso, Eggs, Sugar, Cocoa powder, Marsala wine", Steps = "1. Brew espresso and cool, add Marsala.\n2. Whisk egg yolks and sugar until pale.\n3. Fold in mascarpone cheese.\n4. Whip egg whites, fold into mixture.\n5. Dip ladyfingers in espresso, layer.\n6. Alternate cream and cookies. Chill 4 hours.\n7. Dust with cocoa before serving." },
        };
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe != null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

