@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<h1>
    @(CategoryName switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Japanese" => "🍜",
        "Desserts" => "🍰",
        _ => "🍽️"
    })
    @CategoryName Recipes
</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Models
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/" class="btn btn-secondary">← Back to Home</a>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: <a href="/category/@Recipe.Category">@Recipe.Category</a></p>

    <div class="row">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header">
                    <h3>🥘 Ingredients</h3>
                </div>
                <div class="card-body">
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">
                    <h3>📋 Steps</h3>
                </div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header">
                    <h3>⭐ Rating</h3>
                </div>
                <div class="card-body">
                    <StarRating RecipeId="Recipe.Id" />
                </div>
            </div>
        </div>
    </div>

    <a href="/category/@Recipe.Category" class="btn btn-secondary mt-3">← Back to @Recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div>
    <div class="mb-2">
        @if (AverageRating > 0)
        {
            <p><strong>@AverageRating.ToString("F1")</strong> / 5 (@RatingCount ratings)</p>
        }
        else
        {
            <p class="text-muted">Be the first to rate!</p>
        }
    </div>

    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= HoverRating ? "hovered" : star <= SelectedRating ? "selected" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = 0"
                  role="button"
                  title="@star star(s)">
                @(star <= (HoverRating > 0 ? HoverRating : SelectedRating) ? "★" : "☆")
            </span>
        }
    </div>

    @if (Submitted)
    {
        <p class="text-success mt-2">✓ Thanks for rating!</p>
    }
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star-rating .star.selected,
    .star-rating .star.hovered {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int SelectedRating { get; set; }
    private int HoverRating { get; set; }
    private bool Submitted { get; set; }
    private double AverageRating { get; set; }
    private int RatingCount { get; set; }

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        Submitted = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe != null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@using RecipeHub.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added to the @Model.Category category.</p>
        <a href="/category/@Model.Category" class="btn btn-primary">View in @Model.Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                placeholder="Enter ingredients separated by commas&#10;e.g., Flour, Sugar, Butter, Eggs" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="Model.Steps"
                placeholder="Enter each step on a new line&#10;1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };

        RecipeService.AddRecipe(recipe);
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new RecipeFormModel();
        IsSubmitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

