@inject RecipeService RecipeService

<div>
    <div class="mb-2">
        @if (AverageRating > 0)
        {
            <p><strong>@AverageRating.ToString("F1")</strong> / 5 (@RatingCount ratings)</p>
        }
        else
        {
            <p class="text-muted">Be the first to rate!</p>
        }
    </div>

    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= HoverRating ? "hovered" : star <= SelectedRating ? "selected" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = 0"
                  role="button"
                  title="@star star(s)">
                @(star <= (HoverRating > 0 ? HoverRating : SelectedRating) ? "★" : "☆")
            </span>
        }
    </div>

    @if (Submitted)
    {
        <p class="text-success mt-2">✓ Thanks for rating!</p>
    }
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star-rating .star.selected,
    .star-rating .star.hovered {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int SelectedRating { get; set; }
    private int HoverRating { get; set; }
    private bool Submitted { get; set; }
    private double AverageRating { get; set; }
    private int RatingCount { get; set; }

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        Submitted = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe != null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

