@rendermode InteractiveServer
@using RecipeHub.Services
@using RecipeHub.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added to the @Model.Category category.</p>
        <a href="/category/@Model.Category" class="btn btn-primary">View in @Model.Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                placeholder="Enter ingredients separated by commas&#10;e.g., Flour, Sugar, Butter, Eggs" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="Model.Steps"
                placeholder="Enter each step on a new line&#10;1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };

        RecipeService.AddRecipe(recipe);
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new RecipeFormModel();
        IsSubmitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters")]
        public string Title { get; set; } = string.Empty;

